#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=40005;
int n,ans,p[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
    if(n==1)
	{
		cout<<0;
		return 0;
	}
	for(int i=1;i<=n;i++) p[i]=i;
	for(int i=2;i<=n;i++)
    {
        if(p[i]==i)
        {
            for(int j=i;j<=n;j+=i)
            {
                p[j]=p[j]*(i-1)/i;
            }
        }
    }
    for(int i=1;i<n;i++) ans+=p[i];
    cout<<ans*2+1;
	return 0;
}
